const raw = items[0].json.candidates[0].content.parts[0].text;

const cleaned = raw
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .trim();

const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No JSON found in response: ' + raw);
}

const parsed = JSON.parse(jsonMatch[0]);
return [{ json: parsed }];

const judgeRaw = $('Judge Agent').item.json.candidates[0].content.parts[0].text;
const criticRaw = $('Critic Agent').item.json.candidates[0].content.parts[0].text;

// Unescape HTML entities if Gemini returned escaped HTML
const unescape = (str) => str
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&amp;/g, '&')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

const judgeText = unescape(judgeRaw);
const criticText = unescape(criticRaw);

// Get traveler details
const travelerEmail = $('Parse Gemini Response').item.json.traveler_email;
const destination = $('Parse Gemini Response').item.json.destination_city;

// Generate feedback URL
const feedbackUrl = `http://localhost:5678/form/2d18f3de-bacb-47ee-9a91-3d7dfd28f0f3?email=${encodeURIComponent(travelerEmail)}&destination=${encodeURIComponent(destination)}`;

// Feedback button HTML
const feedbackHtml = `
<div style="text-align:center; margin-top:30px; padding:20px; 
            background-color:#f0f7ff; border-radius:8px; 
            border: 1px solid #d0e8ff;">
  <p style="font-size:16px; color:#333; margin-bottom:12px;">
    Want to refine your itinerary?
  </p>
  <a href="${feedbackUrl}" 
     style="background-color:#0056b3; color:white; padding:12px 28px; 
            text-decoration:none; border-radius:5px; font-size:14px; 
            font-weight:bold; display:inline-block;">
    ✏️ Refine My Itinerary
  </a>
</div>`;

return [{ 
  json: { 
    html_body: judgeText + criticText + feedbackHtml,
    traveler_email: travelerEmail,
    destination: destination
  } 
}];

