const budgetProposal = $('Budget Agent').item.json.candidates[0].content.parts[0].text;
const experienceProposal = $('Experience Agent').item.json.candidates[0].content.parts[0].text;

return [{
  json: {
    budget_proposal: budgetProposal,
    experience_proposal: experienceProposal
  }
}];

const budgetProposal = $('Merge Agent Results').item.json.budget_proposal;
const experienceProposal = $('Merge Agent Results').item.json.experience_proposal;
const travelerName = $('Parse Gemini Response').item.json.traveler_name;
const destination = $('Parse Gemini Response').item.json.destination_city;
const budget = $('Parse Gemini Response').item.json.budget_usd;
const preferences = $('Parse Gemini Response').item.json.preferences;

const prompt = `You are the Judge Agent — a senior travel advisor with 20 years experience. Two agents have submitted competing proposals. Evaluate both and deliver a final recommendation.

TRAVELER: ${travelerName}
DESTINATION: ${destination}
BUDGET: $${budget}
PREFERENCES: ${preferences}

== BUDGET AGENT PROPOSAL ==
${budgetProposal}

== EXPERIENCE AGENT PROPOSAL ==
${experienceProposal}

Your task:
1. Evaluate both proposals fairly
2. Pick the WINNER based on best fit for traveler
3. Explain your reasoning
4. Create a FINAL COMBINED itinerary taking best elements from both

Format as clean HTML for email with sections:
- Judge's Verdict (winner and why)
- What we kept from Budget Agent
- What we kept from Experience Agent
- Final Recommended Itinerary (day by day)
- Estimated Total Cost

Make it personal for ${travelerName}. Output raw HTML only — no markdown, no code fences. Start directly with <!DOCTYPE html>.

STYLING REQUIREMENTS:
- Body font-size must be 14px, line-height 1.6
- h1 font-size: 22px, h2 font-size: 18px, h3 font-size: 15px
- Max-width 700px centered with margin: auto
- The <h1> title and first <p> greeting must be separated — add margin-bottom: 12px to h1
- Keep the email concise — Judge verdict + day-by-day itinerary only, no lengthy preamble`;

const body = JSON.stringify({
  contents: [{
    parts: [{ text: prompt }]
  }]
});

return [{ json: { body } }];

const judgeOutput = $('Judge Agent').item.json.candidates[0].content.parts[0].text;
const travelerName = $('Parse Gemini Response').item.json.traveler_name;
const destination = $('Parse Gemini Response').item.json.destination_city;
const budget = $('Parse Gemini Response').item.json.budget_usd;
const preferences = $('Parse Gemini Response').item.json.preferences;
const departDate = $('Parse Gemini Response').item.json.depart_date;
const returnDate = $('Parse Gemini Response').item.json.return_date;

const prompt = `You are a Devil's Advocate Travel Critic with 20 years of experience spotting hidden problems in travel itineraries. A Judge Agent has produced a final itinerary. Your job is NOT to rewrite it — only to audit it ruthlessly for hidden risks.

TRAVELER: ${travelerName}
DESTINATION: ${destination}
DATES: ${departDate} to ${returnDate}
BUDGET: $${budget}
PREFERENCES: ${preferences}

JUDGE'S ITINERARY:
${judgeOutput}

Audit this itinerary for the following risk categories:

1. LOGISTICS RISKS — layovers under 90 minutes, tight connections, unrealistic travel times between locations
2. BUDGET RISKS — hidden costs (resort fees, taxes, tips, transport between hotel and attractions) that could bust the stated budget
3. EXPERIENCE RISKS — tourist traps, overrated attractions, areas with poor transit or walkability
4. DIETARY RISKS — flag if vegetarian/dietary options may be limited at recommended restaurants or destinations
5. TIMING RISKS — attractions that may be closed on the travel dates, peak season crowds, weather issues

For each risk found, provide:
- Risk level: HIGH / MEDIUM / LOW
- Description of the risk
- Suggested mitigation

Then produce a CRITIC'S VERDICT: a short paragraph summarizing whether the itinerary is APPROVED, APPROVED WITH CAUTIONS, or NEEDS REVISION — and the top 3 action items for the traveler.

Format your entire response as clean HTML, continuing the style of the Judge's itinerary. Start with a section header "🔍 Critic's Risk Assessment" followed by your findings. Output a simple HTML <div> only — no <!DOCTYPE>, no <html>, no <head>, no <body> tags. Max 300 words. Font-size 14px.`;

const body = JSON.stringify({
  contents: [{
    parts: [{ text: prompt }]
  }]
});

return [{ json: { body } }];
